/**
 * Webhook notification handler — dispatches HTTP callbacks when order
 * events occur.
 *
 * Subscribes to EventBus events following the same decoupled pattern as
 * NotificationService and EmailNotificationHandler. External consumers
 * register webhook URLs for specific event types, and this handler
 * POSTs event payloads to those URLs when events fire.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, AppEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: Record<string, unknown>;
  status: 'success' | 'failure';
  statusCode?: number;
  error?: string;
  deliveredAt: Date;
}

export type WebhookSendFn = (
  url: string,
  payload: Record<string, unknown>,
) => Promise<{ ok: boolean; status: number }>;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private sendFn: WebhookSendFn;

  constructor(
    private eventBus: EventBus,
    sendFn?: WebhookSendFn,
  ) {
    this.sendFn = sendFn ?? WebhookHandler.defaultSendFn;
    this.registerHandlers();
  }

  /**
   * Default HTTP sender using the global fetch API.
   */
  private static async defaultSendFn(
    url: string,
    payload: Record<string, unknown>,
  ): Promise<{ ok: boolean; status: number }> {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    return { ok: response.ok, status: response.status };
  }

  /**
   * Register EventBus handlers for order events that trigger webhooks.
   */
  private registerHandlers(): void {
    this.eventBus.on('order:created', (event) => {
      return this.dispatchWebhooks('order:created', event);
    });

    this.eventBus.on('order:status-changed', (event) => {
      return this.dispatchWebhooks('order:status-changed', event);
    });
  }

  /**
   * Register a webhook URL for a specific event type.
   */
  register(url: string, eventType: EventType): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregister(webhookId: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === webhookId);
    if (index < 0) return false;
    this.registrations.splice(index, 1);
    this.logger.info(`Webhook unregistered: ${webhookId}`);
    return true;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clear(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  /**
   * Dispatch webhooks to all URLs registered for a given event type.
   */
  private async dispatchWebhooks(eventType: EventType, event: AppEvent): Promise<void> {
    const matching = this.registrations.filter((r) => r.eventType === eventType);
    if (matching.length === 0) return;

    const payload = this.buildPayload(event);

    for (const registration of matching) {
      await this.deliver(registration, eventType, payload);
    }
  }

  /**
   * Deliver a webhook payload to a single registration.
   */
  private async deliver(
    registration: WebhookRegistration,
    eventType: EventType,
    payload: Record<string, unknown>,
  ): Promise<void> {
    try {
      const result = await this.sendFn(registration.url, payload);

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: registration.id,
        url: registration.url,
        eventType,
        payload,
        status: result.ok ? 'success' : 'failure',
        statusCode: result.status,
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);
      this.logger.info(
        `Webhook delivered: ${delivery.id} to ${registration.url} — ${delivery.status}`,
      );
    } catch (err) {
      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        webhookId: registration.id,
        url: registration.url,
        eventType,
        payload,
        status: 'failure',
        error: err instanceof Error ? err.message : String(err),
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);
      this.logger.info(
        `Webhook delivery failed: ${delivery.id} to ${registration.url} — ${delivery.error}`,
      );
    }
  }

  /**
   * Build a JSON-serializable payload from an event.
   */
  private buildPayload(event: AppEvent): Record<string, unknown> {
    return {
      type: event.type,
      timestamp: event.timestamp.toISOString(),
      ...this.extractEventData(event),
    };
  }

  /**
   * Extract event-specific data fields.
   */
  private extractEventData(event: AppEvent): Record<string, unknown> {
    switch (event.type) {
      case 'order:created':
        return {
          order: event.order,
          user: { id: event.user.id, name: event.user.name, email: event.user.email },
        };
      case 'order:status-changed':
        return {
          order: event.order,
          previousStatus: event.previousStatus,
          newStatus: event.newStatus,
        };
      case 'user:created':
        return { user: event.user };
      case 'user:updated':
        return { user: event.user, changes: event.changes };
    }
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
  type WebhookSendFn,
} from '../../src/notifications/webhook-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

function makeStatusChangedEvent(
  overrides?: Partial<OrderStatusChangedEvent>,
): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let handler: WebhookHandler;
  let mockSend: ReturnType<typeof vi.fn<WebhookSendFn>>;

  beforeEach(() => {
    eventBus = new EventBus();
    mockSend = vi.fn<WebhookSendFn>().mockResolvedValue({ ok: true, status: 200 });
    handler = new WebhookHandler(eventBus, mockSend);
    resetWebhookIdCounters();
  });

  describe('webhook registration', () => {
    it('should register a webhook and return a registration', () => {
      const reg = handler.register('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should list all registrations', () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:status-changed');
      handler.register('https://c.com/hook', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.register('https://a.com/hook', 'order:created');

      expect(handler.unregister(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregister('webhook-9999')).toBe(false);
    });

    it('should generate sequential webhook IDs', () => {
      const r1 = handler.register('https://a.com/hook', 'order:created');
      const r2 = handler.register('https://b.com/hook', 'order:created');

      expect(r1.id).toBe('webhook-0001');
      expect(r2.id).toBe('webhook-0002');
    });
  });

  describe('webhook dispatch on order:created', () => {
    it('should POST to registered URL when order:created fires', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSend).toHaveBeenCalledTimes(1);
      const [url, payload] = mockSend.mock.calls[0]!;
      expect(url).toBe('https://example.com/hook');
      expect(payload.type).toBe('order:created');
      expect(payload.order).toBeDefined();
      expect(payload.user).toBeDefined();
    });

    it('should include order data in the payload', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const payload = mockSend.mock.calls[0]![1];
      const order = payload.order as Record<string, unknown>;
      expect(order.id).toBe('order-1');
      expect(order.total).toBe(20);
    });

    it('should include user data in the payload without sensitive fields', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const payload = mockSend.mock.calls[0]![1];
      const user = payload.user as Record<string, unknown>;
      expect(user.id).toBe('user-1');
      expect(user.name).toBe('Alice');
      expect(user.email).toBe('alice@example.com');
      // Should not include role or timestamps
      expect(user.role).toBeUndefined();
    });

    it('should include ISO timestamp in the payload', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const payload = mockSend.mock.calls[0]![1];
      expect(payload.timestamp).toBe('2026-01-01T00:00:00.000Z');
    });

    it('should not call send if no webhooks are registered for the event', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSend).not.toHaveBeenCalled();
    });

    it('should dispatch to multiple registered URLs', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockSend).toHaveBeenCalledTimes(2);
      expect(mockSend.mock.calls[0]![0]).toBe('https://a.com/hook');
      expect(mockSend.mock.calls[1]![0]).toBe('https://b.com/hook');
    });
  });

  describe('webhook dispatch on order:status-changed', () => {
    it('should POST to registered URL when order:status-changed fires', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent());

      expect(mockSend).toHaveBeenCalledTimes(1);
      const payload = mockSend.mock.calls[0]![1];
      expect(payload.type).toBe('order:status-changed');
      expect(payload.previousStatus).toBe('pending');
      expect(payload.newStatus).toBe('confirmed');
    });

    it('should include order data in status change payload', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent());

      const payload = mockSend.mock.calls[0]![1];
      const order = payload.order as Record<string, unknown>;
      expect(order.id).toBe('order-1');
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('success');
      expect(deliveries[0]?.statusCode).toBe(200);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
    });

    it('should record failed deliveries from non-ok responses', async () => {
      mockSend.mockResolvedValueOnce({ ok: false, status: 500 });
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
      expect(deliveries[0]?.statusCode).toBe(500);
    });

    it('should record failed deliveries from network errors', async () => {
      mockSend.mockRejectedValueOnce(new Error('Connection refused'));
      handler.register('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
      expect(deliveries[0]?.error).toBe('Connection refused');
      expect(deliveries[0]?.statusCode).toBeUndefined();
    });

    it('should track delivery count', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      expect(handler.getDeliveryCount()).toBe(0);

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveryCount()).toBe(2);
    });

    it('should filter deliveries by webhook ID', async () => {
      const r1 = handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForWebhook(r1.id)).toHaveLength(1);
      expect(handler.getDeliveriesForWebhook(r1.id)[0]?.url).toBe('https://a.com/hook');
    });

    it('should generate sequential delivery IDs', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries[0]?.id).toBe('delivery-0001');
      expect(deliveries[1]?.id).toBe('delivery-0002');
    });
  });

  describe('clear', () => {
    it('should clear registrations and deliveries', async () => {
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clear();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });

  describe('coexistence with other handlers', () => {
    it('should work alongside NotificationService and EmailNotificationHandler', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      const { EmailNotificationHandler, resetEmailIdCounter } = await import(
        '../../src/notifications/email-handler.js'
      );
      resetNotificationIdCounter();
      resetEmailIdCounter();

      const notifService = new NotificationService(eventBus);
      const emailHandler = new EmailNotificationHandler(eventBus);

      handler.register('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent());

      expect(notifService.getNotificationCount()).toBe(1);
      expect(emailHandler.getEmailCount()).toBe(1);
      expect(handler.getDeliveryCount()).toBe(1);
    });
  });
});

